    private String getPwdExpDateByPwdDate(String apname, String pwdChgDate){
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy/MM/dd");
        AccountSetting as = Account.getInstance(apname).getAppSetting();
        int period = as.getPwdPeriod();
        String pwdExpdate = "";

        if(!Encoder.isEmptyOrWhitespaceOnly(pwdChgDate)){
            int year = Integer.parseInt(pwdChgDate.split("/")[0]);
            int mon = Integer.parseInt(pwdChgDate.split("/")[1]) -1;
            int day = Integer.parseInt(pwdChgDate.split("/")[2]);

            Calendar baseDate = new GregorianCalendar(year,mon,day);
            if (period>0) {
                baseDate.add(Calendar.DATE, period);
               return sdf.format(baseDate.getTime());
            }
        }

        return pwdExpdate;
    }



